def generate_combinations(dimensions):
    # Extract the keys and value lists from the dictionary
    keys = list(dimensions.keys())
    value_lists = list(dimensions.values())
    
    # Get the Cartesian product of the value lists
    combinations = product(*value_lists)
    
    # Create a list of dictionaries for each combination
    output = [
        dict(zip(keys, combination)) for combination in combinations
    ]
    
    return output

combs = generate_combinations(dimensions_tiny)
for c in combs:
    h=c['hidden']
    c1=c['conv1_size']
    c2=c['conv2_size']
    b=c['batch_size']
    l=c['learning_rate']
    d=c['dropout_rate']
    prefix=f"{c1}-{c2}-{h}-{b}-{l:f}-{d}"
    output_string=f"""mlflow_runname_prefix: "{prefix}-"
conv1_size: {c1}
conv2_size: {c2}
hidden: {h}
batch_size: {b}
learning_rate: {l:f}
dropout_rate: {d}
"""
    print(output_string)

    filename = "part_yaml/"+prefix+".yaml"
    with open(filename, 'w') as file:
        file.write(output_string)

